// Dart imports:
import 'dart:io';

// Package imports:
import 'package:flutter_test/flutter_test.dart';
import 'package:path/path.dart';

final _toolsDir =
    join(dirname(Platform.script.path), 'test', '_testdata', 'tools');

Future<void> restoreDeletedRecords() async {
  final result = await Process.run(
    './restore_records.sh',
    [],
    workingDirectory: _toolsDir,
    runInShell: true,
  );
  expect(result.exitCode, 0);
}

Future<String?> extractVerificationCode(String email) async {
  final result = await Process.run(
    './extract_verification_code.sh',
    [email],
    workingDirectory: _toolsDir,
    runInShell: true,
  );
  expect(result.exitCode, 0);

  final verificationCode = result.stdout.toString().trim();
  return verificationCode.isNotEmpty ? verificationCode : null;
}

// Package imports:
import 'package:collection/collection.dart';
import 'package:freezed_annotation/freezed_annotation.dart';

// Project imports:
import 'package:baseball_detector_flutter/data/models/role_group.dart';
import '../record_definitions.dart';
import 'roles.dart';
import 'teams.dart';

part 'users.freezed.dart';

@freezed
abstract class UserData with _$UserData {
  const UserData._();

  const factory UserData({
    required String id,
    String? name,
    required String email,
    required String? password,
    required String? hashedPassword,
    required Map<String, List<RoleGroup>> roles,
  }) = _UserData;

  String get teamId => roles.keys.first;
}

const _password = 'test1234';
const _hashedPassword =
    '\$2a\$10\$EYApA.H3YC7lAca6dZR8xejKOIJMYG/R6D5Wiu8qcukWYK9AQm6Pu';

final userTeamAdmin = UserData(
  id: '11111111-0000-0000-0000-000000000000',
  name: 'team admin',
  email: 'team_admin@example.co.jp',
  password: _password,
  hashedPassword: _hashedPassword,
  roles: {
    teamMultipleUsers.id!: [roleGroupTeamAdmin]
  },
);

final userTeamManager = UserData(
  id: '22222222-0000-0000-0000-000000000000',
  name: 'team manager',
  email: 'team_manager@example.co.jp',
  password: _password,
  hashedPassword: _hashedPassword,
  roles: {
    teamMultipleUsers.id!: [roleGroupTeamManager],
  },
);

final userTeamMember = UserData(
  id: '33333333-0000-0000-0000-000000000000',
  name: 'team member',
  email: 'team_member@example.co.jp',
  password: _password,
  hashedPassword: _hashedPassword,
  roles: {
    teamMultipleUsers.id!: [roleGroupTeamMember],
  },
);

final userPersonal = UserData(
  id: '44444444-0000-0000-0000-000000000000',
  name: 'personal user',
  email: 'personal@example.co.jp',
  password: _password,
  hashedPassword: _hashedPassword,
  roles: {
    teamPersonal.id!: [roleGroupPersonalUser],
  },
);

final userSuperAdmin = UserData(
  id: '55555555-0000-0000-0000-000000000000',
  name: 'super admin',
  email: 'super_admin@example.co.jp',
  password: _password,
  hashedPassword: _hashedPassword,
  roles: {
    teamSuperAdmin.id!: [roleGroupSuperAdmin],
  },
);

final userWriteTest = UserData(
  id: '66666666-0000-0000-0000-000000000000',
  name: 'to be edited (team admin)',
  email: 'team_admin_write_test@example.co.jp',
  password: _password,
  hashedPassword: _hashedPassword,
  roles: {
    teamWriteTest.id!: [roleGroupTeamAdmin],
  },
);

final userToBeEdited = UserData(
  id: '77777777-0000-0000-0000-000000000000',
  name: 'to be edited (team_member)',
  email: 'team_member_to_be_edited@example.co.jp',
  password: _password,
  hashedPassword: _hashedPassword,
  roles: {
    teamWriteTest.id!: [roleGroupTeamMember],
  },
);

final userToBeActivated = UserData(
  id: '88888888-0000-0000-0000-000000000000',
  name: 'for activation test (team_member)',
  email: 'team_member_for_activation_test@example.co.jp',
  password: _password,
  hashedPassword: _hashedPassword,
  roles: {
    teamWriteTest.id!: [roleGroupTeamMember]
  },
);

final userNotVerified = UserData(
  id: '99999999-0000-0000-0000-000000000000',
  name: 'not verified (team_member)',
  email: 'not_verified@example.co.jp',
  password: null,
  hashedPassword: null,
  roles: {
    teamWriteTest.id!: [roleGroupTeamMember]
  },
);

final _time = DateTime.utc(2024, 1, 1);

final userRecords = RecordDefinitions<UserData>(
  table: 'users',
  data: [
    userTeamAdmin,
    userTeamManager,
    userTeamMember,
    userPersonal,
    userSuperAdmin,
    userWriteTest,
    userToBeEdited,
    userToBeActivated,
    userNotVerified,
  ],
  columns: {
    'id': (e) => e.id,
    'email': (e) => e.email,
    'hashed_password': (e) => e.hashedPassword,
    'created_at': (_) => _time,
    'updated_at': (_) => _time,
  },
);

final profileRecords = RecordDefinitions<UserData>(
  table: 'profiles',
  data: userRecords.data,
  columns: {
    'id': (e) => e.id,
    'username': (e) => e.name,
    'created_at': (_) => _time,
    'updated_at': (_) => _time,
  },
);

typedef RoleRecord = ({String userId, String teamId, RoleGroup roleGroup});

final RecordDefinitions<RoleRecord> userRoleRecords =
    RecordDefinitions<RoleRecord>(
  table: 'user_roles',
  data: (userRecords.data as List<UserData>)
      .map(
        (userData) => userData.roles.entries.map(
          (roleEntry) => roleEntry.value.map(
            (roleGroup) => (
              userId: userData.id,
              teamId: roleEntry.key,
              roleGroup: roleGroup,
            ),
          ),
        ),
      )
      .flattened
      .flattened
      .toList(),
  columns: {
    'id': (e) => e.userId,
    'user_id': (e) => e.userId,
    'team_id': (e) => e.teamId,
    'role': (e) => e.roleGroup.name.toJson(),
    'role_group_id': (e) => e.roleGroup.id,
    'created_at': (_) => _time,
    'updated_at': (_) => _time,
  },
);

